{"content":"package com.pinterest.ktlint.ruleset.standard.rules

import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

internal class IndentationRuleReproTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given a multiline IS_EXPRESSION`() {
        val code =
            """
            fun foo(any: Any) = any is
                    Foo
            """.trimIndent()
        val formattedCode =
            """
            fun foo(any: Any) =
                any is
                    Foo
            """.trimIndent()
        indentationRuleAssertThat(code)
            .asFormattedBy(formattedCode)
    }

    @Test
    fun `Given a multiline PREFIX_EXPRESSION`() {
        val code =
            """
            fun foo(any: Int) = ++
                42
            """.trimIndent()
        // The issue states it is formatted to:
        // fun foo(any: Int) = ++
        // 42
        // Wait, the issue says:
        // fun foo(any: Int) = ++
        //     42
        // Wait, let me re-read.
        /*
        Same for PREFIX_EXPRESSION:
        ```
        fun foo(any: Int) = ++
            42
        ```
        */
        // It doesn't explicitly show what it's formatted TO currently, 
        // but it implies it is also missing indentation.

        val formattedCode =
            """
            fun foo(any: Int) =
                ++
                    42
            """.trimIndent()
        indentationRuleAssertThat(code)
            .asFormattedBy(formattedCode)
    }
}
